// Surface the exit_status and message for n8n's execution log.
// The Telegram message has already been sent by the Python worker.
const r = $input.first().json;
const status = r.exit_status || 'unknown';
const preview = (r.message || '').split('\n')[0] || '(no message)';
return [{ json: { status, preview, summary: r.summary || {} } }];
